SELECT A.SCOLLECT_DT -- 수집일자 , A.SCOLLECT_DT_ORIGIN , A.NROUTING_CHK_MST_SEQ -- 라우팅_비교_결과_SEQ , A.SSVC_LINE_TYPE_CD -- 서비스망_유형_CD , A.SSVC_LINE_TYPE_NM , A.SSVC_GROUP_CD -- 본부/국사_CD , A.SSVC_GROUP_NM , A.SSVC_OBJ_CD -- 노드_CD , A.SSVC_OBJ_NM , A.NLVL_MST_SEQ -- 계위_MST_SEQ , A.NLVL_MST_SEQ2 , A.NIP_ASSIGN_MST_SEQ -- IP_배정_MST_SEQ , A.NIP_ALLOC_MST_SEQ -- IP_할당_MST_SEQ , A.PIPMS_IP_PREFIX -- IPMS_IP , A.SIPMS_IP_BLOCK -- IPMS_IP_블록 , A.NIPMS_IP_BITMASK -- IPMS_IP_비트마스크 , A.NIP_ALLOC_MST_CNT -- 회선 CNT , A.PROUTING_IP_PREFIX -- 라우팅_IP , A.SROUTING_IP_BLOCK -- 라우팅_IP_블록 , A.NROUTING_IP_BITMASK -- 라우팅_IP_비트마스크 , A.SROUTING_USE_YN -- 라우팅_사용_여부 , A.SIP_NEXTHOP -- NEXTHOP , A.SCOMMUNITY -- COMMUNITY , A.SUSE_ROUTING -- 사용장비 , A.SDB_INTGRM_RSLT_CD -- DB현행화_결과 , A.SDB_INTGRM_RSLT_NM -- DB현행화_결과 , A.SSUMMARY_MATCH_YN -- SUMMARY_일치_여부 -- , A.SCOMPARE_CD -- 비교_구분(ASSIGN/ALLOC) , A.SIP_CREATE_TYPE_CD -- IP_생성_유형_CD , A.SIP_CREATE_TYPE_NM , A.SASSIGN_TYPE_CD -- IPMS_서비스_유형_타입_CD , A.SASSIGN_TYPE_NM , A.SASSIGN_LEVEL_CD , A.SASSIGN_LEVEL_NM -- 할당유형상태 , A.SIP_PREFIX_GUBUN , A.NTARGET_CNT , A.SALLOC_GUBUN , A.SIP_GUBUN , A.SEXCPT_YN , A.SEXCPT_YN_ORIGIN , A.SIP_VERSION_TYPE_CD , A.SNEOSS_DD_YN , A.RNUM FROM ( SELECT A.SCOLLECT_DT -- 수집일자 , A.SCOLLECT_DT_ORIGIN , A.NROUTING_CHK_MST_SEQ -- 라우팅_비교_결과_SEQ , A.SSVC_LINE_TYPE_CD -- 서비스망_유형_CD , A.SSVC_LINE_TYPE_NM , A.SSVC_GROUP_CD -- 본부/국사_CD , A.SSVC_GROUP_NM , A.SSVC_OBJ_CD -- 노드_CD , A.SSVC_OBJ_NM , A.NLVL_MST_SEQ -- 계위_MST_SEQ , A.NLVL_MST_SEQ2 , A.NIP_ASSIGN_MST_SEQ -- IP_배정_MST_SEQ , A.NIP_ALLOC_MST_SEQ -- IP_할당_MST_SEQ , A.PIPMS_IP_PREFIX -- IPMS_IP , A.SIPMS_IP_BLOCK -- IPMS_IP_블록 , A.NIPMS_IP_BITMASK -- IPMS_IP_비트마스크 , A.NIP_ALLOC_MST_CNT -- 회선 CNT , A.PROUTING_IP_PREFIX -- 라우팅_IP , A.SROUTING_IP_BLOCK -- 라우팅_IP_블록 , A.NROUTING_IP_BITMASK -- 라우팅_IP_비트마스크 , A.SROUTING_USE_YN -- 라우팅_사용_여부 , A.SIP_NEXTHOP -- NEXTHOP , A.SCOMMUNITY -- COMMUNITY , A.SUSE_ROUTING -- 사용장비 , A.SDB_INTGRM_RSLT_CD -- DB현행화_결과 , A.SDB_INTGRM_RSLT_NM -- DB현행화_결과 , A.SSUMMARY_MATCH_YN -- SUMMARY_일치_여부 -- , A.SCOMPARE_CD -- 비교_구분(ASSIGN/ALLOC) , A.SIP_CREATE_TYPE_CD -- IP_생성_유형_CD , A.SIP_CREATE_TYPE_NM , A.SASSIGN_TYPE_CD -- IPMS_서비스_유형_타입_CD , A.SASSIGN_TYPE_NM , A.SASSIGN_LEVEL_CD , A.SASSIGN_LEVEL_NM -- 할당유형상태 , A.SIP_PREFIX_GUBUN , A.NTARGET_CNT , A.SALLOC_GUBUN , A.SIP_GUBUN , A.SEXCPT_YN , A.SEXCPT_YN_ORIGIN , A.SIP_VERSION_TYPE_CD , A.SNEOSS_DD_YN , ROWNUM RNUM FROM ( SELECT A.SCOLLECT_DT -- 수집일자 , A.PIP_PREFIX , A.NBITMASK , A.SCOLLECT_DT_ORIGIN , A.NROUTING_CHK_MST_SEQ -- 라우팅_비교_결과_SEQ , A.SSVC_LINE_TYPE_CD -- 서비스망_유형_CD , A.SSVC_LINE_TYPE_NM , A.SSVC_GROUP_CD -- 본부/국사_CD , A.SSVC_GROUP_NM , A.SSVC_OBJ_CD -- 노드_CD , A.SSVC_OBJ_NM , A.NLVL_MST_SEQ -- 계위_MST_SEQ , A.NLVL_MST_SEQ2 , A.NIP_ASSIGN_MST_SEQ -- IP_배정_MST_SEQ , A.NIP_ALLOC_MST_SEQ -- IP_할당_MST_SEQ , A.PIPMS_IP_PREFIX -- IPMS_IP , A.SIPMS_IP_BLOCK -- IPMS_IP_블록 , A.NIPMS_IP_BITMASK -- IPMS_IP_비트마스크 , A.NIP_ALLOC_MST_CNT -- 회선 CNT , A.PROUTING_IP_PREFIX -- 라우팅_IP , A.SROUTING_IP_BLOCK -- 라우팅_IP_블록 , A.NROUTING_IP_BITMASK -- 라우팅_IP_비트마스크 , A.SROUTING_USE_YN -- 라우팅_사용_여부 , A.SIP_NEXTHOP -- NEXTHOP , A.SCOMMUNITY -- COMMUNITY , A.SUSE_ROUTING -- 사용장비 , A.SDB_INTGRM_RSLT_CD -- DB현행화_결과 , A.SDB_INTGRM_RSLT_NM -- DB현행화_결과 , A.SSUMMARY_MATCH_YN -- SUMMARY_일치_여부 -- , A.SCOMPARE_CD -- 비교_구분(ASSIGN/ALLOC) , A.SIP_CREATE_TYPE_CD -- IP_생성_유형_CD , A.SIP_CREATE_TYPE_NM , A.SASSIGN_TYPE_CD -- IPMS_서비스_유형_타입_CD , A.SASSIGN_TYPE_NM , A.SASSIGN_LEVEL_CD , A.SASSIGN_LEVEL_NM -- 할당유형상태 , A.SIP_PREFIX_GUBUN , A.NTARGET_CNT , (CASE WHEN A.SEXCPT_YN_ORIGIN = 'Y' THEN '-' ELSE (CASE WHEN A.NTARGET_CNT > 0 THEN '-' WHEN A.SIPMS_IP_BLOCK = A.SROUTING_IP_BLOCK AND A.NIPMS_IP_BITMASK = A.NROUTING_IP_BITMASK AND A.NTARGET_CNT = 0 AND A.SASSIGN_LEVEL_CD IN ('IA0001', 'IA0002', 'IA0003', 'IA0004') THEN (CASE WHEN A.SROUTING_USE_YN_ORIGIN = 'Y' THEN 'ALLOC' ELSE '-' END) WHEN A.SIPMS_IP_BLOCK = A.SROUTING_IP_BLOCK AND A.NIPMS_IP_BITMASK = A.NROUTING_IP_BITMASK AND A.NTARGET_CNT = 0 AND A.SASSIGN_LEVEL_CD IN ('IA0006') THEN (CASE WHEN A.SROUTING_USE_YN_ORIGIN = 'N' THEN 'ASSIGN' ELSE '-' END) WHEN A.SIPMS_IP_BLOCK = A.SROUTING_IP_BLOCK AND A.NIPMS_IP_BITMASK = A.NROUTING_IP_BITMASK AND A.NTARGET_CNT = 0 AND A.SASSIGN_LEVEL_CD IN ('IA0005') THEN '-' ELSE '-' END) END) AS SALLOC_GUBUN -- 할당예약은 장비 미사용으로 봄 (opration 진행 x) , A.SIP_GUBUN , A.SEXCPT_YN , A.SEXCPT_YN_ORIGIN , A.SIP_VERSION_TYPE_CD , A.SNEOSS_DD_YN FROM ( SELECT TO_CHAR(TO_DATE(SUBSTRING(A.SCOLLECT_DT, 1, 8)), 'YYYY-MM-DD') AS SCOLLECT_DT -- 수집일자 , B.PIP_PREFIX , B.NBITMASK , A.SCOLLECT_DT AS SCOLLECT_DT_ORIGIN , A.NROUTING_CHK_MST_SEQ -- 라우팅_비교_결과_SEQ , A.SSVC_LINE_TYPE_CD -- 서비스망_유형_CD , G.SSVC_LINE_TYPE_NM , D.SSVC_GROUP_CD -- 본부/국사_CD , E.SLVL_NM AS SSVC_GROUP_NM , D.SSVC_OBJ_CD -- 노드_CD , F.SLVL_NM AS SSVC_OBJ_NM , A.NLVL_MST_SEQ -- 계위_MST_SEQ , O.NMAX_SEQ AS NLVL_MST_SEQ2 , NVL(A.NIP_CHG_ASSIGN_MST_SEQ, A.NIP_ASSIGN_MST_SEQ) AS NIP_ASSIGN_MST_SEQ -- IP_배정_MST_SEQ , (CASE WHEN A.NIP_CHG_ASSIGN_MST_SEQ IS NOT NULL THEN A.NIP_CHG_ALLOC_MST_SEQ ELSE A.NIP_ALLOC_MST_SEQ END) AS NIP_ALLOC_MST_SEQ -- IP_할당_MST_SEQ , (CASE WHEN A.NIP_CHG_ASSIGN_MST_SEQ IS NOT NULL THEN B.PIP_PREFIX ELSE (CASE WHEN A.SDB_INTGRM_RSLT_CD = 'DR0004' THEN A.PROUTING_IP_PREFIX ELSE A.PIPMS_IP_PREFIX END) END) AS PIPMS_IP_PREFIX -- IPMS_IP , (CASE WHEN A.NIP_CHG_ASSIGN_MST_SEQ IS NOT NULL THEN B.SIP_BLOCK ELSE (CASE WHEN A.SDB_INTGRM_RSLT_CD = 'DR0004' THEN A.SROUTING_IP_BLOCK ELSE A.SIPMS_IP_BLOCK END) END) AS SIPMS_IP_BLOCK -- IPMS_IP_블록 , (CASE WHEN A.NIP_CHG_ASSIGN_MST_SEQ IS NOT NULL THEN B.NBITMASK ELSE (CASE WHEN A.SDB_INTGRM_RSLT_CD = 'DR0004' THEN A.NROUTING_IP_BITMASK ELSE A.NIPMS_IP_BITMASK END) END) AS NIPMS_IP_BITMASK -- IPMS_IP_비트마스크 , B.NIP_ALLOC_MST_CNT -- 회선 CNT , A.PROUTING_IP_PREFIX -- 라우팅_IP , A.SROUTING_IP_BLOCK -- 라우팅_IP_블록 , A.NROUTING_IP_BITMASK -- 라우팅_IP_비트마스크 , A.SROUTING_USE_YN AS SROUTING_USE_YN_ORIGIN , (CASE WHEN A.SROUTING_USE_YN = 'Y' THEN '사용' ELSE '미사용' END) AS SROUTING_USE_YN -- 라우팅_사용_여부 , (CASE WHEN A.SIP_NEXTHOP IS NULL OR A.SIP_NEXTHOP = '' THEN '-' ELSE A.SIP_NEXTHOP END) AS SIP_NEXTHOP -- NEXTHOP , (CASE WHEN A.SCOMMUNITY IS NULL OR A.SCOMMUNITY = '' THEN '-' ELSE A.SCOMMUNITY END) AS SCOMMUNITY -- COMMUNITY , (CASE WHEN A.SUSE_ROUTING IS NULL OR A.SUSE_ROUTING = '' THEN '-' ELSE A.SUSE_ROUTING END) AS SUSE_ROUTING -- 사용장비 , A.SDB_INTGRM_RSLT_CD , (CASE WHEN A.SDB_INTGRM_RSLT_CD IS NULL OR A.SDB_INTGRM_RSLT_CD = '' THEN '-' ELSE M.SDB_INTGRM_RSLT_NM END) AS SDB_INTGRM_RSLT_NM -- DB현행화_결과 , A.SSUMMARY_MATCH_YN -- SUMMARY_일치_여부 , A.SCOMPARE_CD -- 비교_구분(ASSIGN/ALLOC) , B.SIP_CREATE_TYPE_CD -- IP_생성_유형_CD , H.SIP_CREATE_TYPE_NM , B.SASSIGN_TYPE_CD -- IPMS_서비스_유형_타입_CD , I.SASSIGN_TYPE_NM , B.SASSIGN_LEVEL_CD , J.SASSIGN_LEVEL_NM -- 할당유형상태 , L.SIP_PREFIX_GUBUN , (CASE WHEN A.SDB_INTGRM_RSLT_CD = 'DR0002' OR A.SDB_INTGRM_RSLT_CD = 'DR0004' THEN 0 WHEN A.SDB_INTGRM_RSLT_CD IS NULL THEN L.NTARGET_CNT ELSE L.NTARGET_CNT END) AS NTARGET_CNT , (CASE WHEN A.SDB_INTGRM_RSLT_CD = 'DR0002' OR A.SDB_INTGRM_RSLT_CD = 'DR0004' THEN 'SAME' ELSE L.SIP_GUBUN END) AS SIP_GUBUN , (CASE WHEN A.SEXCPT_YN = 'N' THEN '-' ELSE '예외' END) AS SEXCPT_YN , A.SEXCPT_YN AS SEXCPT_YN_ORIGIN , B.SIP_VERSION_TYPE_CD , I.SNEOSS_DD_YN FROM MST.TB_INTGRM_ROUTING_CHK_MST A -- 라우팅_비교_결과_MST , MST.TB_IP_ASSIGN_MST B -- IP_배정_MST , MST.TB_IP_ALLOC_MST C -- IP_할당_MST , MST.TB_LVL_MST D -- 계위_MST_수동계위포함 , MST.TB_LVL_CD E -- 국사/조직코드_수동포함 , MST.TB_LVL_CD F -- 국사/조직코드_수동포함 , MST.TB_SVC_LINE_TYPE_CD G -- 서비스_망_유형_CD , MST.TB_IP_CREATE_TYPE_CD H -- IP_생성_유형_CD , MST.TB_ASSIGN_TYPE_CD I -- IP_SVC_할당유형_CD 코넷-기업-고정 , MST.TB_ASSIGN_LEVEL_CD J -- 단계레벨_CD 생성(미배정)/예비배정/본배정/선배정/할당예약/할당확정
, ( SELECT ROWNUM AS Seq , TIP, DECODE(BIF.UF_CHECK_IP(TIP), 'N',INET('0.0.0.0/32') , CIDR(INET(TIP))) AS MMA FROM( SELECT TRIM(unnest(STRING_TO_ARRAY(REPLACE(REPLACE(REPLACE(#{searchWrdMulti, jdbcType=VARCHAR},CHR(9),','),CHR(10),','),' ',',') ,','))) AS TIP FROM DUAL ) MA WHERE TIP IS NOT NULL AND TIP !='' ) K
, ( SELECT A.SCOLLECT_DT , A.NROUTING_CHK_MST_SEQ , (CASE WHEN A.CASE1 > 1 AND A.CASE2 = 1 THEN 'PIPMS' -- ROUTING 장비 IP 범위가 더 작을 경우(분할) WHEN A.CASE2 > 1 AND A.CASE1 = 1 THEN 'PROUTING' -- IPMS IP 범위가 더 작을 경우(병합) WHEN A.CASE1 = 1 AND A.CASE2 = 1 THEN 'PIPMS' -- IP 범위 같을 경우 ELSE NULL END) AS SIP_PREFIX_GUBUN , (CASE WHEN A.CASE1 > 1 AND A.CASE2 = 1 THEN A.CASE1 -- ROUTING 장비 IP 범위가 더 작을 경우(분할) WHEN A.CASE2 > 1 AND A.CASE1 = 1 THEN A.CASE2 -- IPMS IP 범위가 더 작을 경우(병합) WHEN A.CASE1 = 1 AND A.CASE2 = 1 THEN 0 -- IP 범위 같을 경우 ELSE 0 END) AS NTARGET_CNT , (CASE WHEN A.CASE1 > 1 AND A.CASE2 = 1 THEN 'BIG' -- ROUTING 장비 IP 범위가 더 작을 경우(분할) WHEN A.CASE2 > 1 AND A.CASE1 = 1 THEN 'SMALL' -- IPMS IP 범위가 더 작을 경우(병합) WHEN A.CASE1 = 1 AND A.CASE2 = 1 THEN 'SAME' -- IP 범위 같을 경우 ELSE NULL END) AS SIP_GUBUN FROM ( SELECT A.SCOLLECT_DT , A.NROUTING_CHK_MST_SEQ , COUNT(A.PIPMS_IP_PREFIX) OVER(PARTITION BY A.SCOLLECT_DT, A.SSVC_LINE_TYPE_CD, A.PIPMS_IP_PREFIX) AS CASE1 , COUNT(A.PROUTING_IP_PREFIX) OVER(PARTITION BY A.SCOLLECT_DT, A.SSVC_LINE_TYPE_CD, A.PROUTING_IP_PREFIX) AS CASE2 FROM MST.TB_INTGRM_ROUTING_CHK_MST A WHERE 1=1 AND A.SCHANGE_YN = 'N' -- IP배정, IP할당 메뉴에서 변경이 일어난 건은 조회X AND (A.SCOLLECT_DT, A.NLVL_MST_SEQ) IN ( SELECT MAX(SCOLLECT_DT), NLVL_MST_SEQ FROM MST.TB_INTGRM_ROUTING_CHK_MST WHERE 1=1 AND SCHANGE_YN = 'N' -- IP배정, IP할당 메뉴에서 변경이 일어난 건은 조회X AND NLVL_MST_SEQ IN ( SELECT NLVL_MST_SEQ FROM MST.TB_LVL_MST WHERE 1=1
AND NLVL_MST_SEQ IN
#{item.nlvlSeq}
) GROUP BY NLVL_MST_SEQ ) ) A WHERE 1=1 ) L , MST.TB_INTGRM_RSLT_CD M -- DB현행화결과 CD , MST.TB_LVL_BAS O WHERE 1=1 AND (A.SCOLLECT_DT, A.NLVL_MST_SEQ) IN ( SELECT MAX(SCOLLECT_DT), NLVL_MST_SEQ FROM MST.TB_INTGRM_ROUTING_CHK_MST WHERE 1=1 AND SCHANGE_YN = 'N' -- IP배정, IP할당 메뉴에서 변경이 일어난 건은 조회X AND NLVL_MST_SEQ IN ( SELECT NLVL_MST_SEQ FROM MST.TB_LVL_MST WHERE 1=1
AND NLVL_MST_SEQ IN
#{item.nlvlSeq}
) GROUP BY NLVL_MST_SEQ) AND B.NIP_ASSIGN_MST_SEQ = NVL(A.NIP_CHG_ASSIGN_MST_SEQ, A.NIP_ASSIGN_MST_SEQ) AND C.NIP_ASSIGN_MST_SEQ(+) = NVL(A.NIP_CHG_ASSIGN_MST_SEQ, A.NIP_ASSIGN_MST_SEQ) AND C.NIP_ALLOC_MST_SEQ(+) = NVL(A.NIP_CHG_ALLOC_MST_SEQ, A.NIP_ALLOC_MST_SEQ) AND D.NLVL_MST_SEQ = A.NLVL_MST_SEQ AND E.SLVL_CD(+) = D.SSVC_GROUP_CD AND F.SLVL_CD(+) = D.SSVC_OBJ_CD AND G.SSVC_LINE_TYPE_CD(+) = D.SSVC_LINE_TYPE_CD AND H.SIP_CREATE_TYPE_CD(+) = B.SIP_CREATE_TYPE_CD AND I.SASSIGN_TYPE_CD(+) = B.SASSIGN_TYPE_CD AND J.SASSIGN_LEVEL_CD(+) = B.SASSIGN_LEVEL_CD AND L.SCOLLECT_DT(+) = A.SCOLLECT_DT AND L.NROUTING_CHK_MST_SEQ(+) = A.NROUTING_CHK_MST_SEQ AND M.SDB_INTGRM_RSLT_CD(+) = A.SDB_INTGRM_RSLT_CD AND A.SCHANGE_YN = 'N' -- IP배정, IP할당 메뉴에서 변경이 일어난 건은 조회X AND O.SSVC_LINE_TYPE_CD = A.SSVC_LINE_TYPE_CD(+) AND O.SSVC_GROUP_CD = D.SSVC_GROUP_CD(+) AND O.SSVC_OBJ_CD = D.SSVC_OBJ_CD(+)
AND A.SSVC_LINE_TYPE_CD = #{ssvcLineTypeCd, jdbcType=CHAR}
AND A.NLVL_MST_SEQ IN
#{item.nlvlSeq}
AND (B.PIP_PREFIX >>= (SELECT BIF.UF_SEARCH_IP_TO_ADDRESS(#{searchWrd, jdbcType=VARCHAR}) AS SIP FROM DUAL) OR B.PIP_PREFIX <<= (SELECT BIF.UF_SEARCH_IP_TO_ADDRESS(#{searchWrd, jdbcType=VARCHAR}) AS SIP FROM DUAL) OR A.PROUTING_IP_PREFIX >>= (SELECT BIF.UF_SEARCH_IP_TO_ADDRESS(#{searchWrd, jdbcType=VARCHAR}) AS SIP FROM DUAL) OR A.PROUTING_IP_PREFIX <<= (SELECT BIF.UF_SEARCH_IP_TO_ADDRESS(#{searchWrd, jdbcType=VARCHAR}) AS SIP FROM DUAL) )
AND (A.NIPMS_IP_BITMASK = #{nbitmask, jdbcType=INTEGER} OR A.NROUTING_IP_BITMASK = #{nbitmask, jdbcType=INTEGER})
AND B.SASSIGN_LEVEL_CD = #{sassignLevelCd, jdbcType=CHAR}
AND B.SASSIGN_TYPE_CD IN
#{item}
AND B.SASSIGN_LEVEL_CD IN
#{item}
AND B.SIP_CREATE_TYPE_CD = #{sipCreateTypeCd, jdbcType=CHAR}
AND (CASE WHEN A.SDB_INTGRM_RSLT_CD = 'DR0002' OR A.SDB_INTGRM_RSLT_CD = 'DR0004' THEN 'SAME' ELSE L.SIP_GUBUN END) = #{skindCd, jdbcType=CHAR}
AND (CASE WHEN A.SDB_INTGRM_RSLT_CD = 'DR0002' OR A.SDB_INTGRM_RSLT_CD = 'DR0004' THEN 0 WHEN A.SDB_INTGRM_RSLT_CD IS NULL THEN L.NTARGET_CNT ELSE L.NTARGET_CNT END) >= #{ngubunCnt, jdbcType=INTEGER}
AND (CASE WHEN A.SDB_INTGRM_RSLT_CD = 'DR0002' OR A.SDB_INTGRM_RSLT_CD = 'DR0004' THEN 0 WHEN A.SDB_INTGRM_RSLT_CD IS NULL THEN L.NTARGET_CNT ELSE L.NTARGET_CNT END) <= #{ngubunCnt, jdbcType=INTEGER}
AND (CASE WHEN A.SDB_INTGRM_RSLT_CD = 'DR0002' OR A.SDB_INTGRM_RSLT_CD = 'DR0004' THEN 0 WHEN A.SDB_INTGRM_RSLT_CD IS NULL THEN L.NTARGET_CNT ELSE L.NTARGET_CNT END) = #{ngubunCnt, jdbcType=INTEGER}
AND (K.MMA <<= B.PIP_PREFIX OR K.MMA >>= B.PIP_PREFIX)
AND A.SDB_INTGRM_RSLT_CD = #{sdbIntgrmRsltCd, jdbcType=VARCHAR}
AND A.SEXCPT_YN = #{sexcpt_yn, jdbcType=VARCHAR}
) A GROUP BY A.SCOLLECT_DT -- 수집일자 , A.PIP_PREFIX , A.NBITMASK , A.SCOLLECT_DT_ORIGIN , A.NROUTING_CHK_MST_SEQ -- 라우팅_비교_결과_SEQ , A.SSVC_LINE_TYPE_CD -- 서비스망_유형_CD , A.SSVC_LINE_TYPE_NM , A.SSVC_GROUP_CD -- 본부/국사_CD , A.SSVC_GROUP_NM , A.SSVC_OBJ_CD -- 노드_CD , A.SSVC_OBJ_NM , A.NLVL_MST_SEQ -- 계위_MST_SEQ , A.NLVL_MST_SEQ2 , A.NIP_ASSIGN_MST_SEQ -- IP_배정_MST_SEQ , A.NIP_ALLOC_MST_SEQ -- IP_할당_MST_SEQ , A.PIPMS_IP_PREFIX -- IPMS_IP , A.SIPMS_IP_BLOCK -- IPMS_IP_블록 , A.NIPMS_IP_BITMASK -- IPMS_IP_비트마스크 , A.NIP_ALLOC_MST_CNT -- 회선 CNT , A.PROUTING_IP_PREFIX -- 라우팅_IP , A.SROUTING_IP_BLOCK -- 라우팅_IP_블록 , A.NROUTING_IP_BITMASK -- 라우팅_IP_비트마스크 , A.SROUTING_USE_YN -- 라우팅_사용_여부 , A.SIP_NEXTHOP -- NEXTHOP , A.SCOMMUNITY -- COMMUNITY , A.SUSE_ROUTING -- 사용장비 , A.SDB_INTGRM_RSLT_CD -- DB현행화_결과 , A.SDB_INTGRM_RSLT_NM -- DB현행화_결과 , A.SSUMMARY_MATCH_YN -- SUMMARY_일치_여부 -- , A.SCOMPARE_CD -- 비교_구분(ASSIGN/ALLOC) , A.SIP_CREATE_TYPE_CD -- IP_생성_유형_CD , A.SIP_CREATE_TYPE_NM , A.SASSIGN_TYPE_CD -- IPMS_서비스_유형_타입_CD , A.SASSIGN_TYPE_NM , A.SASSIGN_LEVEL_CD , A.SASSIGN_LEVEL_NM -- 할당유형상태 , A.SIP_PREFIX_GUBUN , A.NTARGET_CNT , A.SROUTING_USE_YN_ORIGIN , A.SIP_GUBUN , A.SEXCPT_YN , A.SEXCPT_YN_ORIGIN , A.SIP_VERSION_TYPE_CD , A.SNEOSS_DD_YN
