SELECT count(1) totalCount FROM ( SELECT (CASE WHEN A.SDB_INTGRM_RSLT_CD = 'DR0002' OR A.SDB_INTGRM_RSLT_CD = 'DR0004' THEN B.PIP_PREFIX ELSE (CASE WHEN L.SIP_PREFIX_GUBUN = 'PROUTING' THEN A.PROUTING_IP_PREFIX ELSE A.PIPMS_IP_PREFIX END) END) AS PIP_PREFIX FROM MST.TB_INTGRM_ROUTING_CHK_MST A -- 라우팅_비교_결과_MST , MST.TB_IP_ASSIGN_MST B -- IP_배정_MST , MST.TB_IP_ALLOC_MST C -- IP_할당_MST , MST.TB_LVL_MST D -- 계위_MST_수동계위포함 , MST.TB_LVL_CD E -- 국사/조직코드_수동포함 , MST.TB_LVL_CD F -- 국사/조직코드_수동포함 , MST.TB_SVC_LINE_TYPE_CD G -- 서비스_망_유형_CD , MST.TB_IP_CREATE_TYPE_CD H -- IP_생성_유형_CD , MST.TB_ASSIGN_TYPE_CD I -- IP_SVC_할당유형_CD 코넷-기업-고정 , MST.TB_ASSIGN_LEVEL_CD J -- 단계레벨_CD 생성(미배정)/예비배정/본배정/선배정/할당예약/할당확정
, ( SELECT ROWNUM AS Seq , TIP, DECODE(BIF.UF_CHECK_IP(TIP), 'N',INET('0.0.0.0/32') , CIDR(INET(TIP))) AS MMA FROM( SELECT TRIM(unnest(STRING_TO_ARRAY(REPLACE(REPLACE(REPLACE(#{searchWrdMulti, jdbcType=VARCHAR},CHR(9),','),CHR(10),','),' ',',') ,','))) AS TIP FROM DUAL ) MA WHERE TIP IS NOT NULL AND TIP !='' ) K
, ( SELECT A.SCOLLECT_DT , A.NROUTING_CHK_MST_SEQ , (CASE WHEN A.CASE1 > 1 AND A.CASE2 = 1 THEN 'PIPMS' -- ROUTING 장비 IP 범위가 더 작을 경우(분할) WHEN A.CASE2 > 1 AND A.CASE1 = 1 THEN 'PROUTING' -- IPMS IP 범위가 더 작을 경우(병합) WHEN A.CASE1 = 1 AND A.CASE2 = 1 THEN 'PIPMS' -- IP 범위 같을 경우 ELSE NULL END) AS SIP_PREFIX_GUBUN , (CASE WHEN A.CASE1 > 1 AND A.CASE2 = 1 THEN A.CASE1 -- ROUTING 장비 IP 범위가 더 작을 경우(분할) WHEN A.CASE2 > 1 AND A.CASE1 = 1 THEN A.CASE2 -- IPMS IP 범위가 더 작을 경우(병합) WHEN A.CASE1 = 1 AND A.CASE2 = 1 THEN 0 -- IP 범위 같을 경우 ELSE 0 END) AS NTARGET_CNT , (CASE WHEN A.CASE1 > 1 AND A.CASE2 = 1 THEN 'BIG' -- ROUTING 장비 IP 범위가 더 작을 경우(분할) WHEN A.CASE2 > 1 AND A.CASE1 = 1 THEN 'SMALL' -- IPMS IP 범위가 더 작을 경우(병합) WHEN A.CASE1 = 1 AND A.CASE2 = 1 THEN 'SAME' -- IP 범위 같을 경우 ELSE NULL END) AS SIP_GUBUN FROM ( SELECT A.SCOLLECT_DT , A.NROUTING_CHK_MST_SEQ , COUNT(A.PIPMS_IP_PREFIX) OVER(PARTITION BY A.SCOLLECT_DT, A.SSVC_LINE_TYPE_CD, A.PIPMS_IP_PREFIX) AS CASE1 , COUNT(A.PROUTING_IP_PREFIX) OVER(PARTITION BY A.SCOLLECT_DT, A.SSVC_LINE_TYPE_CD, A.PROUTING_IP_PREFIX) AS CASE2 FROM MST.TB_INTGRM_ROUTING_CHK_MST A WHERE 1=1 AND A.SCHANGE_YN = 'N' -- IP배정, IP할당 메뉴에서 변경이 일어난 건은 조회X AND (A.SCOLLECT_DT, A.NLVL_MST_SEQ) IN ( SELECT MAX(SCOLLECT_DT), NLVL_MST_SEQ FROM MST.TB_INTGRM_ROUTING_CHK_MST WHERE 1=1 AND SCHANGE_YN = 'N' -- IP배정, IP할당 메뉴에서 변경이 일어난 건은 조회X AND NLVL_MST_SEQ IN ( SELECT NLVL_MST_SEQ FROM MST.TB_LVL_MST WHERE 1=1
AND NLVL_MST_SEQ IN
#{item.nlvlSeq}
) GROUP BY NLVL_MST_SEQ ) ) A WHERE 1=1 ) L , MST.TB_INTGRM_RSLT_CD M -- DB현행화결과 CD , MST.TB_LVL_BAS O WHERE 1=1 AND (A.SCOLLECT_DT, A.NLVL_MST_SEQ) IN ( SELECT MAX(SCOLLECT_DT), NLVL_MST_SEQ FROM MST.TB_INTGRM_ROUTING_CHK_MST WHERE 1=1 AND SCHANGE_YN = 'N' -- IP배정, IP할당 메뉴에서 변경이 일어난 건은 조회X AND NLVL_MST_SEQ IN ( SELECT NLVL_MST_SEQ FROM MST.TB_LVL_MST WHERE 1=1
AND NLVL_MST_SEQ IN
#{item.nlvlSeq}
) GROUP BY NLVL_MST_SEQ) AND B.NIP_ASSIGN_MST_SEQ = NVL(A.NIP_CHG_ASSIGN_MST_SEQ, A.NIP_ASSIGN_MST_SEQ) AND C.NIP_ASSIGN_MST_SEQ(+) = NVL(A.NIP_CHG_ASSIGN_MST_SEQ, A.NIP_ASSIGN_MST_SEQ) AND C.NIP_ALLOC_MST_SEQ(+) = NVL(A.NIP_CHG_ALLOC_MST_SEQ, A.NIP_ALLOC_MST_SEQ) AND D.NLVL_MST_SEQ = A.NLVL_MST_SEQ AND E.SLVL_CD(+) = D.SSVC_GROUP_CD AND F.SLVL_CD(+) = D.SSVC_OBJ_CD AND G.SSVC_LINE_TYPE_CD(+) = D.SSVC_LINE_TYPE_CD AND H.SIP_CREATE_TYPE_CD(+) = B.SIP_CREATE_TYPE_CD AND I.SASSIGN_TYPE_CD(+) = B.SASSIGN_TYPE_CD AND J.SASSIGN_LEVEL_CD(+) = B.SASSIGN_LEVEL_CD AND L.SCOLLECT_DT(+) = A.SCOLLECT_DT AND L.NROUTING_CHK_MST_SEQ(+) = A.NROUTING_CHK_MST_SEQ AND M.SDB_INTGRM_RSLT_CD(+) = A.SDB_INTGRM_RSLT_CD AND A.SCHANGE_YN = 'N' -- IP배정, IP할당 메뉴에서 변경이 일어난 건은 조회X AND O.SSVC_LINE_TYPE_CD = A.SSVC_LINE_TYPE_CD(+) AND O.SSVC_GROUP_CD = D.SSVC_GROUP_CD(+) AND O.SSVC_OBJ_CD = D.SSVC_OBJ_CD(+)
AND A.SSVC_LINE_TYPE_CD = #{ssvcLineTypeCd, jdbcType=CHAR}
AND A.NLVL_MST_SEQ IN
#{item.nlvlSeq}
AND (B.PIP_PREFIX >>= (SELECT BIF.UF_SEARCH_IP_TO_ADDRESS(#{searchWrd, jdbcType=VARCHAR}) AS SIP FROM DUAL) OR B.PIP_PREFIX <<= (SELECT BIF.UF_SEARCH_IP_TO_ADDRESS(#{searchWrd, jdbcType=VARCHAR}) AS SIP FROM DUAL) OR A.PROUTING_IP_PREFIX >>= (SELECT BIF.UF_SEARCH_IP_TO_ADDRESS(#{searchWrd, jdbcType=VARCHAR}) AS SIP FROM DUAL) OR A.PROUTING_IP_PREFIX <<= (SELECT BIF.UF_SEARCH_IP_TO_ADDRESS(#{searchWrd, jdbcType=VARCHAR}) AS SIP FROM DUAL) )
AND (A.NIPMS_IP_BITMASK = #{nbitmask, jdbcType=INTEGER} OR A.NROUTING_IP_BITMASK = #{nbitmask, jdbcType=INTEGER})
AND B.SASSIGN_LEVEL_CD = #{sassignLevelCd, jdbcType=CHAR}
AND B.SASSIGN_TYPE_CD IN
#{item}
AND B.SASSIGN_LEVEL_CD IN
#{item}
AND B.SIP_CREATE_TYPE_CD = #{sipCreateTypeCd, jdbcType=CHAR}
AND (CASE WHEN A.SDB_INTGRM_RSLT_CD = 'DR0002' OR A.SDB_INTGRM_RSLT_CD = 'DR0004' THEN 'SAME' ELSE L.SIP_GUBUN END) = #{skindCd, jdbcType=CHAR}
AND (CASE WHEN A.SDB_INTGRM_RSLT_CD = 'DR0002' OR A.SDB_INTGRM_RSLT_CD = 'DR0004' THEN 0 WHEN A.SDB_INTGRM_RSLT_CD IS NULL THEN L.NTARGET_CNT ELSE L.NTARGET_CNT END) >= #{ngubunCnt, jdbcType=INTEGER}
AND (CASE WHEN A.SDB_INTGRM_RSLT_CD = 'DR0002' OR A.SDB_INTGRM_RSLT_CD = 'DR0004' THEN 0 WHEN A.SDB_INTGRM_RSLT_CD IS NULL THEN L.NTARGET_CNT ELSE L.NTARGET_CNT END) <= #{ngubunCnt, jdbcType=INTEGER}
AND (CASE WHEN A.SDB_INTGRM_RSLT_CD = 'DR0002' OR A.SDB_INTGRM_RSLT_CD = 'DR0004' THEN 0 WHEN A.SDB_INTGRM_RSLT_CD IS NULL THEN L.NTARGET_CNT ELSE L.NTARGET_CNT END) = #{ngubunCnt, jdbcType=INTEGER}
AND (K.MMA <<= B.PIP_PREFIX OR K.MMA >>= B.PIP_PREFIX)
AND A.SDB_INTGRM_RSLT_CD = #{sdbIntgrmRsltCd, jdbcType=VARCHAR}
AND A.SEXCPT_YN = #{sexcpt_yn, jdbcType=VARCHAR}
GROUP BY (CASE WHEN A.SDB_INTGRM_RSLT_CD = 'DR0002' OR A.SDB_INTGRM_RSLT_CD = 'DR0004' THEN B.PIP_PREFIX ELSE (CASE WHEN L.SIP_PREFIX_GUBUN = 'PROUTING' THEN A.PROUTING_IP_PREFIX ELSE A.PIPMS_IP_PREFIX END) END) )

SELECT A.SCOLLECT_DT , A.NROUTING_CHK_MST_SEQ , A.SSVC_LINE_TYPE_CD , A.NLVL_MST_SEQ , B.NIP_ASSIGN_MST_SEQ --, NVL(A.NIP_CHG_ASSIGN_MST_SEQ, A.NIP_ASSIGN_MST_SEQ) AS NIP_ASSIGN_MST_SEQ , C.NIP_ALLOC_MST_SEQ , (CASE WHEN A.NIP_CHG_ASSIGN_MST_SEQ IS NOT NULL THEN B.PIP_PREFIX ELSE A.PIPMS_IP_PREFIX END) AS PIPMS_IP_PREFIX -- IPMS_IP , (CASE WHEN A.NIP_CHG_ASSIGN_MST_SEQ IS NOT NULL THEN B.SIP_BLOCK ELSE A.SIPMS_IP_BLOCK END) AS SIPMS_IP_BLOCK -- IPMS_IP_블록 , (CASE WHEN A.NIP_CHG_ASSIGN_MST_SEQ IS NOT NULL THEN B.NBITMASK ELSE A.NIPMS_IP_BITMASK END) AS NIPMS_IP_BITMASK -- IPMS_IP_비트마스크 , B.NIP_ALLOC_MST_CNT -- 회선 CNT , A.PROUTING_IP_PREFIX -- 라우팅_IP , A.SROUTING_IP_BLOCK -- 라우팅_IP_블록 , A.NROUTING_IP_BITMASK -- 라우팅_IP_비트마스크 , B.SIP_VERSION_TYPE_CD , B.SASSIGN_LEVEL_CD , B.NIP_BLOCK_MST_SEQ , B.SASSIGN_TYPE_CD , A.PROUTING_IP_PREFIX AS PIP_PREFIX -- 분할/병합 대상 ip , A.NROUTING_IP_BITMASK AS NBITMASK -- 분할/병합 대상 bitmask , (SELECT NWHOIS_SEQ FROM BIF.TB_WHOIS WHERE (CASE WHEN A.NIP_CHG_ASSIGN_MST_SEQ IS NOT NULL THEN B.PIP_PREFIX ELSE A.PIPMS_IP_PREFIX END) = PIP_PREFIX AND NVL(A.NIP_CHG_ASSIGN_MST_SEQ, A.NIP_ASSIGN_MST_SEQ) = TO_NUMBER(RIGHT(ssaid,12)) LIMIT 1) AS NWHOIS_SEQ , A.SEXCPT_YN , A.SROUTING_USE_YN FROM MST.TB_INTGRM_ROUTING_CHK_MST A , MST.TB_IP_ASSIGN_MST B , MST.TB_IP_ALLOC_MST C WHERE 1=1 AND (A.SCOLLECT_DT, A.NLVL_MST_SEQ) IN ( SELECT MAX(A.SCOLLECT_DT), A.NLVL_MST_SEQ FROM MST.TB_INTGRM_ROUTING_CHK_MST A , MST.TB_LVL_MST B WHERE 1=1 AND A.SCHANGE_YN = 'N' -- IP배정, IP할당 메뉴에서 변경이 일어난 건은 조회X AND B.NLVL_MST_SEQ = A.NLVL_MST_SEQ AND (B.SSVC_LINE_TYPE_CD, B.SSVC_GROUP_CD, B.SSVC_OBJ_CD) IN ( SELECT SSVC_LINE_TYPE_CD, SSVC_GROUP_CD, SSVC_OBJ_CD FROM MST.TB_LVL_MST WHERE 1=1
AND NLVL_MST_SEQ = #{nlvlMstSeq, jdbcType=BIGINT}
) GROUP BY A.NLVL_MST_SEQ) AND B.NIP_ASSIGN_MST_SEQ = NVL(A.NIP_CHG_ASSIGN_MST_SEQ, A.NIP_ASSIGN_MST_SEQ) AND C.NIP_ASSIGN_MST_SEQ(+) = B.NIP_ASSIGN_MST_SEQ AND A.SCHANGE_YN = 'N' -- IP배정, IP할당 메뉴에서 변경이 일어난 건은 조회X AND A.SEXCPT_YN = 'N'
AND B.SASSIGN_LEVEL_CD IN ('IA0005', 'IA0006')
AND (CASE WHEN #{sipPrefixGubun, jdbcType=CHAR} = 'PIPMS' THEN A.PIPMS_IP_PREFIX WHEN #{sipPrefixGubun, jdbcType=CHAR} = 'PROUTING' THEN A.PROUTING_IP_PREFIX END) = ((CASE WHEN #{sipPrefixGubun, jdbcType=CHAR} = 'PIPMS' THEN (SELECT PIPMS_IP_PREFIX FROM MST.TB_INTGRM_ROUTING_CHK_MST WHERE 1=1 AND SCHANGE_YN = 'N' -- IP배정, IP할당 메뉴에서 변경이 일어난 건은 조회X AND (SCOLLECT_DT, NLVL_MST_SEQ) IN ( SELECT MAX(A.SCOLLECT_DT), A.NLVL_MST_SEQ FROM MST.TB_INTGRM_ROUTING_CHK_MST A , MST.TB_LVL_MST B WHERE 1=1 AND A.SCHANGE_YN = 'N' -- IP배정, IP할당 메뉴에서 변경이 일어난 건은 조회X AND B.NLVL_MST_SEQ = A.NLVL_MST_SEQ AND (B.SSVC_LINE_TYPE_CD, B.SSVC_GROUP_CD, B.SSVC_OBJ_CD) IN ( SELECT SSVC_LINE_TYPE_CD, SSVC_GROUP_CD, SSVC_OBJ_CD FROM MST.TB_LVL_MST WHERE 1=1
AND NLVL_MST_SEQ = #{nlvlMstSeq, jdbcType=BIGINT}
) GROUP BY A.NLVL_MST_SEQ) AND NROUTING_CHK_MST_SEQ = #{nroutingChkMstSeq, jdbcType=BIGINT}) WHEN #{sipPrefixGubun, jdbcType=CHAR} = 'PROUTING' THEN (SELECT PROUTING_IP_PREFIX FROM MST.TB_INTGRM_ROUTING_CHK_MST WHERE 1=1 AND SCHANGE_YN = 'N' -- IP배정, IP할당 메뉴에서 변경이 일어난 건은 조회X AND (SCOLLECT_DT, NLVL_MST_SEQ) IN ( SELECT MAX(A.SCOLLECT_DT), A.NLVL_MST_SEQ FROM MST.TB_INTGRM_ROUTING_CHK_MST A , MST.TB_LVL_MST B WHERE 1=1 AND A.SCHANGE_YN = 'N' -- IP배정, IP할당 메뉴에서 변경이 일어난 건은 조회X AND B.NLVL_MST_SEQ = A.NLVL_MST_SEQ AND (B.SSVC_LINE_TYPE_CD, B.SSVC_GROUP_CD, B.SSVC_OBJ_CD) IN ( SELECT SSVC_LINE_TYPE_CD, SSVC_GROUP_CD, SSVC_OBJ_CD FROM MST.TB_LVL_MST WHERE 1=1
AND NLVL_MST_SEQ = #{nlvlMstSeq, jdbcType=BIGINT}
) GROUP BY A.NLVL_MST_SEQ) AND NROUTING_CHK_MST_SEQ = #{nroutingChkMstSeq, jdbcType=BIGINT}) END))

