) GROUP BY A.NLVL_MST_SEQ) AND A.NROUTING_CHK_MST_SEQ = #{nroutingChkMstSeq, jdbcType=BIGINT} AND A.NLVL_MST_SEQ = #{nlvlMstSeq, jdbcType=BIGINT} AND B.PIP_PREFIX(+) = A.PROUTING_IP_PREFIX)
, A.DSTAT_DT = SYSDATE , A.NIP_CHG_ASSIGN_MST_SEQ = (SELECT MAX(B.NIP_ASSIGN_MST_SEQ) FROM MST.TB_INTGRM_ROUTING_CHK_MST A , MST.TB_IP_ASSIGN_MST B WHERE 1=1 AND A.SCHANGE_YN = 'N' -- IP배정, IP할당 메뉴에서 변경이 일어난 건은 조회X AND (A.SCOLLECT_DT, A.NLVL_MST_SEQ) IN ( SELECT MAX(A.SCOLLECT_DT), A.NLVL_MST_SEQ FROM MST.TB_INTGRM_ROUTING_CHK_MST A , MST.TB_LVL_MST B WHERE 1=1 AND A.SCHANGE_YN = 'N' -- IP배정, IP할당 메뉴에서 변경이 일어난 건은 조회X AND B.NLVL_MST_SEQ = A.NLVL_MST_SEQ AND (B.SSVC_LINE_TYPE_CD, B.SSVC_GROUP_CD, B.SSVC_OBJ_CD) IN ( SELECT SSVC_LINE_TYPE_CD, SSVC_GROUP_CD, SSVC_OBJ_CD FROM MST.TB_LVL_MST WHERE 1=1
AND NLVL_MST_SEQ = #{nlvlMstSeq, jdbcType=BIGINT}
) GROUP BY A.NLVL_MST_SEQ) AND A.NROUTING_CHK_MST_SEQ = #{nroutingChkMstSeq, jdbcType=BIGINT} AND A.NLVL_MST_SEQ = #{nlvlMstSeq, jdbcType=BIGINT} AND B.PIP_PREFIX(+) = A.PROUTING_IP_PREFIX) , A.NIP_CHG_ALLOC_MST_SEQ = (SELECT MAX(C.NIP_ALLOC_MST_SEQ) FROM MST.TB_INTGRM_ROUTING_CHK_MST A , MST.TB_IP_ALLOC_MST C WHERE 1=1 AND A.SCHANGE_YN = 'N' -- IP배정, IP할당 메뉴에서 변경이 일어난 건은 조회X AND (A.SCOLLECT_DT, A.NLVL_MST_SEQ) IN ( SELECT MAX(A.SCOLLECT_DT), A.NLVL_MST_SEQ FROM MST.TB_INTGRM_ROUTING_CHK_MST A , MST.TB_LVL_MST B WHERE 1=1 AND A.SCHANGE_YN = 'N' -- IP배정, IP할당 메뉴에서 변경이 일어난 건은 조회X AND B.NLVL_MST_SEQ = A.NLVL_MST_SEQ AND (B.SSVC_LINE_TYPE_CD, B.SSVC_GROUP_CD, B.SSVC_OBJ_CD) IN ( SELECT SSVC_LINE_TYPE_CD, SSVC_GROUP_CD, SSVC_OBJ_CD FROM MST.TB_LVL_MST WHERE 1=1
AND NLVL_MST_SEQ = #{nlvlMstSeq, jdbcType=BIGINT}
) GROUP BY A.NLVL_MST_SEQ) AND A.NROUTING_CHK_MST_SEQ = #{nroutingChkMstSeq, jdbcType=BIGINT} AND A.NLVL_MST_SEQ = #{nlvlMstSeq, jdbcType=BIGINT} AND C.PIP_PREFIX(+) = A.PROUTING_IP_PREFIX)
, A.SEXCPT_YN = #{sexcpt_yn, jdbcType=VARCHAR}
WHERE 1=1 AND A.SCHANGE_YN = 'N' -- IP배정, IP할당 메뉴에서 변경이 일어난 건은 조회X AND (A.SCOLLECT_DT, A.NLVL_MST_SEQ) IN ( SELECT MAX(A.SCOLLECT_DT), A.NLVL_MST_SEQ FROM MST.TB_INTGRM_ROUTING_CHK_MST A , MST.TB_LVL_MST B WHERE 1=1 AND A.SCHANGE_YN = 'N' -- IP배정, IP할당 메뉴에서 변경이 일어난 건은 조회X AND B.NLVL_MST_SEQ = A.NLVL_MST_SEQ AND (B.SSVC_LINE_TYPE_CD, B.SSVC_GROUP_CD, B.SSVC_OBJ_CD) IN ( SELECT SSVC_LINE_TYPE_CD, SSVC_GROUP_CD, SSVC_OBJ_CD FROM MST.TB_LVL_MST WHERE 1=1
AND NLVL_MST_SEQ = #{nlvlMstSeq, jdbcType=BIGINT}
) GROUP BY A.NLVL_MST_SEQ)
AND A.NROUTING_CHK_MST_SEQ = #{nroutingChkMstSeq, jdbcType=BIGINT}
AND A.NROUTING_CHK_MST_SEQ = #{nroutingChkMstSeq, jdbcType=BIGINT}
AND A.NROUTING_CHK_MST_SEQ = #{nroutingChkMstSeq, jdbcType=BIGINT}
AND A.NROUTING_CHK_MST_SEQ IN ( SELECT NROUTING_CHK_MST_SEQ FROM MST.TB_INTGRM_ROUTING_CHK_MST WHERE 1=1 AND SCHANGE_YN = 'N' -- IP배정, IP할당 메뉴에서 변경이 일어난 건은 조회X AND (SCOLLECT_DT, NLVL_MST_SEQ) IN ( SELECT MAX(A.SCOLLECT_DT), A.NLVL_MST_SEQ FROM MST.TB_INTGRM_ROUTING_CHK_MST A , MST.TB_LVL_MST B WHERE 1=1 AND A.SCHANGE_YN = 'N' -- IP배정, IP할당 메뉴에서 변경이 일어난 건은 조회X AND B.NLVL_MST_SEQ = A.NLVL_MST_SEQ AND (B.SSVC_LINE_TYPE_CD, B.SSVC_GROUP_CD, B.SSVC_OBJ_CD) IN ( SELECT SSVC_LINE_TYPE_CD, SSVC_GROUP_CD, SSVC_OBJ_CD FROM MST.TB_LVL_MST WHERE 1=1
AND NLVL_MST_SEQ = #{nlvlMstSeq, jdbcType=BIGINT}
) GROUP BY A.NLVL_MST_SEQ) AND A.NLVL_MST_SEQ = #{nlvlMstSeq, jdbcType=BIGINT} AND (CASE WHEN #{sipPrefixGubun, jdbcType=CHAR} = 'PIPMS' THEN A.PIPMS_IP_PREFIX WHEN #{sipPrefixGubun, jdbcType=CHAR} = 'PROUTING' THEN A.PROUTING_IP_PREFIX END) = ( SELECT (CASE WHEN #{sipPrefixGubun, jdbcType=CHAR} = 'PIPMS' THEN (SELECT PIPMS_IP_PREFIX FROM MST.TB_INTGRM_ROUTING_CHK_MST WHERE SCOLLECT_DT = #{scollectDtOrigin, jdbcType=VARCHAR} AND NLVL_MST_SEQ = #{nlvlMstSeq, jdbcType=BIGINT} AND NROUTING_CHK_MST_SEQ = #{nroutingChkMstSeq, jdbcType=BIGINT}) WHEN #{sipPrefixGubun, jdbcType=CHAR} = 'PROUTING' THEN (SELECT PROUTING_IP_PREFIX FROM MST.TB_INTGRM_ROUTING_CHK_MST WHERE SCOLLECT_DT = #{scollectDtOrigin, jdbcType=VARCHAR} AND NLVL_MST_SEQ = #{nlvlMstSeq, jdbcType=BIGINT} AND NROUTING_CHK_MST_SEQ = #{nroutingChkMstSeq, jdbcType=BIGINT}) END) ) )

