, A.SMODIFY_ID = #{smodifyId, jdbcType=VARCHAR}
, A.SEXCPT_YN = #{sexcpt_yn, jdbcType=VARCHAR}
WHERE 1=1 AND NVL(A.SDB_INTGRM_RSLT_CD, 'X') NOT IN ('DR0004', 'DR0002') AND A.SCHANGE_YN = 'N' -- IP배정, IP할당 메뉴에서 변경이 일어난 건은 조회X AND (A.SCOLLECT_DT, A.NLVL_MST_SEQ) IN ( SELECT MAX(A.SCOLLECT_DT), A.NLVL_MST_SEQ FROM MST.TB_INTGRM_ROUTING_CHK_MST A , MST.TB_LVL_MST B WHERE 1=1 AND A.SCHANGE_YN = 'N' -- IP배정, IP할당 메뉴에서 변경이 일어난 건은 조회X AND B.NLVL_MST_SEQ = A.NLVL_MST_SEQ AND (B.SSVC_LINE_TYPE_CD, B.SSVC_GROUP_CD, B.SSVC_OBJ_CD) IN ( SELECT SSVC_LINE_TYPE_CD, SSVC_GROUP_CD, SSVC_OBJ_CD FROM MST.TB_LVL_MST WHERE 1=1 ) GROUP BY A.NLVL_MST_SEQ) AND A.NROUTING_CHK_MST_SEQ IN ( SELECT A.NROUTING_CHK_MST_SEQ FROM MST.TB_INTGRM_ROUTING_CHK_MST A , ( SELECT A.SCOLLECT_DT , A.NROUTING_CHK_MST_SEQ , (CASE WHEN A.CASE1 > 1 AND A.CASE2 = 1 THEN 'PIPMS' -- ROUTING 장비 IP 범위가 더 작을 경우(분할) WHEN A.CASE2 > 1 AND A.CASE1 = 1 THEN 'PROUTING' -- IPMS IP 범위가 더 작을 경우(병합) WHEN A.CASE1 = 1 AND A.CASE2 = 1 THEN 'PIPMS' -- IP 범위 같을 경우 ELSE NULL END) AS SIP_PREFIX_GUBUN FROM ( SELECT A.SCOLLECT_DT , A.NROUTING_CHK_MST_SEQ , A.CASE1 , A.CASE2 FROM ( SELECT A.SCOLLECT_DT , A.NROUTING_CHK_MST_SEQ , COUNT(A.PIPMS_IP_PREFIX) OVER(PARTITION BY A.SCOLLECT_DT, A.SSVC_LINE_TYPE_CD, A.PIPMS_IP_PREFIX) AS CASE1 , COUNT(A.PROUTING_IP_PREFIX) OVER(PARTITION BY A.SCOLLECT_DT, A.SSVC_LINE_TYPE_CD, A.PROUTING_IP_PREFIX) AS CASE2 FROM MST.TB_INTGRM_ROUTING_CHK_MST A WHERE 1=1 AND A.SCHANGE_YN = 'N' -- IP배정, IP할당 메뉴에서 변경이 일어난 건은 조회X AND (A.SCOLLECT_DT, A.NLVL_MST_SEQ) IN ( SELECT MAX(SCOLLECT_DT), NLVL_MST_SEQ FROM MST.TB_INTGRM_ROUTING_CHK_MST WHERE 1=1 AND SCHANGE_YN = 'N' -- IP배정, IP할당 메뉴에서 변경이 일어난 건은 조회X AND NLVL_MST_SEQ IN ( SELECT NLVL_MST_SEQ FROM MST.TB_LVL_MST WHERE 1=1 ) GROUP BY NLVL_MST_SEQ ) ) A WHERE 1=1 AND A.NROUTING_CHK_MST_SEQ = #{nroutingChkMstSeq, jdbcType=BIGINT} ) A WHERE 1=1 ) B WHERE 1=1 AND A.SCHANGE_YN = 'N' -- IP배정, IP할당 메뉴에서 변경이 일어난 건은 조회X AND (A.SCOLLECT_DT, A.NLVL_MST_SEQ) IN ( SELECT MAX(SCOLLECT_DT), NLVL_MST_SEQ FROM MST.TB_INTGRM_ROUTING_CHK_MST WHERE 1=1 AND SCHANGE_YN = 'N' -- IP배정, IP할당 메뉴에서 변경이 일어난 건은 조회X AND NLVL_MST_SEQ IN ( SELECT NLVL_MST_SEQ FROM MST.TB_LVL_MST WHERE 1=1 ) GROUP BY NLVL_MST_SEQ) AND NVL(A.SDB_INTGRM_RSLT_CD, '') <> 'DR0004' -- DB현행화 성공 제외 AND (CASE WHEN B.SIP_PREFIX_GUBUN = 'PIPMS' THEN A.PIPMS_IP_PREFIX WHEN B.SIP_PREFIX_GUBUN = 'PROUTING' THEN A.PROUTING_IP_PREFIX END) = ((CASE WHEN B.SIP_PREFIX_GUBUN = 'PIPMS' THEN (SELECT PIPMS_IP_PREFIX FROM MST.TB_INTGRM_ROUTING_CHK_MST WHERE (SCOLLECT_DT, NLVL_MST_SEQ) IN ( SELECT MAX(SCOLLECT_DT), NLVL_MST_SEQ FROM MST.TB_INTGRM_ROUTING_CHK_MST WHERE 1=1 AND NLVL_MST_SEQ IN ( SELECT NLVL_MST_SEQ FROM MST.TB_LVL_MST WHERE 1=1 ) GROUP BY NLVL_MST_SEQ) AND NROUTING_CHK_MST_SEQ = #{nroutingChkMstSeq, jdbcType=BIGINT}) WHEN B.SIP_PREFIX_GUBUN = 'PROUTING' THEN (SELECT PROUTING_IP_PREFIX FROM MST.TB_INTGRM_ROUTING_CHK_MST WHERE (SCOLLECT_DT, NLVL_MST_SEQ) IN ( SELECT MAX(SCOLLECT_DT), NLVL_MST_SEQ FROM MST.TB_INTGRM_ROUTING_CHK_MST WHERE 1=1 AND NLVL_MST_SEQ IN ( SELECT NLVL_MST_SEQ FROM MST.TB_LVL_MST WHERE 1=1 ) GROUP BY NLVL_MST_SEQ) AND NROUTING_CHK_MST_SEQ = #{nroutingChkMstSeq, jdbcType=BIGINT}) END))
)

mapper.delete:
DELETE FROM MST.TB_INTGRM_ROUTING_EXCPT_MST A WHERE 1=1 AND (A.SSVC_LINE_TYPE_CD, A.NLVL_MST_SEQ, A.NIP_ASSIGN_MST_SEQ, A.PIPMS_IP_PREFIX) IN ( SELECT A.SSVC_LINE_TYPE_CD , A.NLVL_MST_SEQ , A.NIP_ASSIGN_MST_SEQ , A.PIPMS_IP_PREFIX FROM MST.TB_INTGRM_ROUTING_CHK_MST A , MST.TB_IP_ASSIGN_MST B WHERE 1=1 AND A.SCHANGE_YN = 'N' -- IP배정, IP할당 메뉴에서 변경이 일어난 건은 조회X AND (A.SCOLLECT_DT, A.NLVL_MST_SEQ) IN ( SELECT MAX(SCOLLECT_DT), NLVL_MST_SEQ FROM MST.TB_INTGRM_ROUTING_CHK_MST WHERE 1=1 AND SCHANGE_YN = 'N' -- IP배정, IP할당 메뉴에서 변경이 일어난 건은 조회X AND NLVL_MST_SEQ IN ( SELECT NLVL_MST_SEQ FROM MST.TB_LVL_MST WHERE 1=1
AND NLVL_MST_SEQ = #{nlvlMstSeq, jdbcType=BIGINT}
) GROUP BY NLVL_MST_SEQ) AND A.NLVL_MST_SEQ = #{nlvlMstSeq, jdbcType=BIGINT} AND B.NIP_ASSIGN_MST_SEQ = NVL(A.NIP_CHG_ASSIGN_MST_SEQ, A.NIP_ASSIGN_MST_SEQ) AND (CASE WHEN #{sipPrefixGubun, jdbcType=CHAR} = 'PIPMS' THEN A.PIPMS_IP_PREFIX WHEN #{sipPrefixGubun, jdbcType=CHAR} = 'PROUTING' THEN A.PROUTING_IP_PREFIX END) = ((CASE WHEN #{sipPrefixGubun, jdbcType=CHAR} = 'PIPMS' THEN (SELECT PIPMS_IP_PREFIX FROM MST.TB_INTGRM_ROUTING_CHK_MST WHERE (SCOLLECT_DT, NLVL_MST_SEQ) IN ( SELECT MAX(SCOLLECT_DT), NLVL_MST_SEQ FROM MST.TB_INTGRM_ROUTING_CHK_MST WHERE 1=1 AND NLVL_MST_SEQ IN ( SELECT NLVL_MST_SEQ FROM MST.TB_LVL_MST WHERE 1=1
AND NLVL_MST_SEQ = #{nlvlMstSeq, jdbcType=BIGINT}
) GROUP BY NLVL_MST_SEQ) AND NROUTING_CHK_MST_SEQ = #{nroutingChkMstSeq, jdbcType=BIGINT}) WHEN #{sipPrefixGubun, jdbcType=CHAR} = 'PROUTING' THEN (SELECT PROUTING_IP_PREFIX FROM MST.TB_INTGRM_ROUTING_CHK_MST WHERE (SCOLLECT_DT, NLVL_MST_SEQ) IN ( SELECT MAX(SCOLLECT_DT), NLVL_MST_SEQ FROM MST.TB_INTGRM_ROUTING_CHK_MST WHERE 1=1 AND NLVL_MST_SEQ IN ( SELECT NLVL_MST_SEQ FROM MST.TB_LVL_MST WHERE 1=1
AND NLVL_MST_SEQ = #{nlvlMstSeq, jdbcType=BIGINT}
) GROUP BY NLVL_MST_SEQ) AND NROUTING_CHK_MST_SEQ = #{nroutingChkMstSeq, jdbcType=BIGINT}) END)) )

mapper.select:
SELECT (CASE WHEN mst.uf_get_intgrm_assign_change(A.SCOLLECT_DT, A.SSVC_LINE_TYPE_CD, B.SIP_CREATE_TYPE_CD, A.PROUTING_IP_PREFIX) = 'Y' THEN (CASE WHEN #{sipPrefixGubun, jdbcType=CHAR} = 'PIPMS' THEN A.PIPMS_IP_PREFIX ELSE A.PROUTING_IP_PREFIX END) ELSE NULL END) AS PROUTING_IP_PREFIX FROM MST.TB_INTGRM_ROUTING_CHK_MST A , MST.TB_IP_ASSIGN_MST B WHERE 1=1 AND A.SCHANGE_YN = 'N' -- IP배정, IP할당 메뉴에서 변경이 일어난 건은 조회X AND B.NIP_ASSIGN_MST_SEQ = NVL(A.NIP_CHG_ASSIGN_MST_SEQ, A.NIP_ASSIGN_MST_SEQ) AND (A.SCOLLECT_DT, A.NLVL_MST_SEQ) IN ( SELECT MAX(A.SCOLLECT_DT), A.NLVL_MST_SEQ FROM MST.TB_INTGRM_ROUTING_CHK_MST A , MST.TB_LVL_MST B WHERE 1=1 AND A.SCHANGE_YN = 'N' -- IP배정, IP할당 메뉴에서 변경이 일어난 건은 조회X AND B.NLVL_MST_SEQ = A.NLVL_MST_SEQ AND (B.SSVC_LINE_TYPE_CD, B.SSVC_GROUP_CD, B.SSVC_OBJ_CD) IN ( SELECT SSVC_LINE_TYPE_CD, SSVC_GROUP_CD, SSVC_OBJ_CD FROM MST.TB_LVL_MST WHERE 1=1
AND NLVL_MST_SEQ = #{nlvlMstSeq, jdbcType=BIGINT}
) GROUP BY A.NLVL_MST_SEQ) AND A.NROUTING_CHK_MST_SEQ = #{nroutingChkMstSeq, jdbcType=BIGINT}

SELECT TO_CHAR(TO_DATE(SUBSTRING(A.SCOLLECT_DT, 1, 8)), 'YYYY-MM-DD') AS SCOLLECT_DT -- 수집일자 , B.PIP_PREFIX , B.NBITMASK , A.SCOLLECT_DT AS SCOLLECT_DT_ORIGIN , A.NROUTING_CHK_MST_SEQ -- 라우팅_비교_결과_SEQ , A.SSVC_LINE_TYPE_CD -- 서비스망_유형_CD , G.SSVC_LINE_TYPE_NM , D.SSVC_GROUP_CD -- 본부/국사_CD , E.SLVL_NM AS SSVC_GROUP_NM , D.SSVC_OBJ_CD -- 노드_CD , F.SLVL_NM AS SSVC_OBJ_NM , A.NLVL_MST_SEQ -- 계위_MST_SEQ , NVL(A.NIP_CHG_ASSIGN_MST_SEQ, A.NIP_ASSIGN_MST_SEQ) AS NIP_ASSIGN_MST_SEQ -- IP_배정_MST_SEQ , (CASE WHEN A.NIP_CHG_ASSIGN_MST_SEQ IS NOT NULL THEN A.NIP_CHG_ALLOC_MST_SEQ ELSE A.NIP_ALLOC_MST_SEQ END) AS NIP_ALLOC_MST_SEQ -- IP_할당_MST_SEQ , (CASE WHEN A.NIP_CHG_ASSIGN_MST_SEQ IS NOT NULL THEN B.PIP_PREFIX ELSE A.PIPMS_IP_PREFIX END) AS PIPMS_IP_PREFIX -- IPMS_IP , (CASE WHEN A.NIP_CHG_ASSIGN_MST_SEQ IS NOT NULL THEN B.SIP_BLOCK ELSE A.SIPMS_IP_BLOCK END) AS SIPMS_IP_BLOCK -- IPMS_IP_블록 , (CASE WHEN A.NIP_CHG_ASSIGN_MST_SEQ IS NOT NULL THEN B.NBITMASK ELSE A.NIPMS_IP_BITMASK END) AS NIPMS_IP_BITMASK -- IPMS_IP_비트마스크 , B.NIP_ALLOC_MST_CNT -- 회선 CNT , A.PROUTING_IP_PREFIX -- 라우팅_IP , A.SROUTING_IP_BLOCK -- 라우팅_IP_블록 , A.NROUTING_IP_BITMASK -- 라우팅_IP_비트마스크 , A.SROUTING_USE_YN AS SROUTING_USE_YN_ORIGIN , (CASE WHEN A.SROUTING_USE_YN = 'Y' THEN '사용' ELSE '미사용' END) AS SROUTING_USE_YN -- 라우팅_사용_여부 , (CASE WHEN A.SIP_NEXTHOP IS NULL OR A.SIP_NEXTHOP = '' THEN '-' ELSE A.SIP_NEXTHOP END) AS SIP_NEXTHOP -- NEXTHOP , (CASE WHEN A.SCOMMUNITY IS NULL OR A.SCOMMUNITY = '' THEN '-' ELSE A.SCOMMUNITY END) AS SCOMMUNITY -- COMMUNITY , (CASE WHEN A.SUSE_ROUTING IS NULL OR A.SUSE_ROUTING = '' THEN '-' ELSE A.SUSE_ROUTING END) AS SUSE_ROUTING -- 사용장비 , A.SDB_INTGRM_RSLT_CD , (CASE WHEN A.SDB_INTGRM_RSLT_CD IS NULL OR A.SDB_INTGRM_RSLT_CD = '' THEN '-' ELSE M.SDB_INTGRM_RSLT_NM END) AS SDB_INTGRM_RSLT_NM -- DB현행화_결과 , A.SSUMMARY_MATCH_YN -- SUMMARY_일치_여부 , A.SCOMPARE_CD -- 비교_구분(ASSIGN/ALLOC) , B.SIP_CREATE_TYPE_CD -- IP_생성_유형_CD , H.SIP_CREATE_TYPE_NM , B.SASSIGN_TYPE_CD -- IPMS_서비스_유형_타입_CD , I.SASSIGN_TYPE_NM , B.SASSIGN_LEVEL_CD , J.SASSIGN_LEVEL_NM -- 할당유형상태 , L.SIP_PREFIX_GUBUN , (CASE WHEN A.SDB_INTGRM_RSLT_CD = 'DR0002' OR A.SDB_INTGRM_RSLT_CD = 'DR0004' THEN 0 WHEN A.SDB_INTGRM_RSLT_CD IS NULL THEN L.NTARGET_CNT ELSE L.NTARGET_CNT END) AS NTARGET_CNT , L.SIP_GUBUN , (CASE WHEN NVL(A.SEXCPT_YN, 'N') = 'N' THEN '-' ELSE '예외' END) AS SEXCPT_YN , NVL(A.SEXCPT_YN, 'N') AS SEXCPT_YN_ORIGIN , B.SIP_VERSION_TYPE_CD FROM MST.TB_INTGRM_ROUTING_CHK_MST A -- 라우팅_비교_결과_MST , MST.TB_IP_ASSIGN_MST B -- IP_배정_MST , MST.TB_IP_ALLOC_MST C -- IP_할당_MST , MST.TB_LVL_MST D -- 계위_MST_수동계위포함 , MST.TB_LVL_CD E -- 국사/조직코드_수동포함 , MST.TB_LVL_CD F -- 국사/조직코드_수동포함 , MST.TB_SVC_LINE_TYPE_CD G -- 서비스_망_유형_CD , MST.TB_IP_CREATE_TYPE_CD H -- IP_생성_유형_CD , MST.TB_ASSIGN_TYPE_CD I -- IP_SVC_할당유형_CD 코넷-기업-고정 , MST.TB_ASSIGN_LEVEL_CD J -- 단계레벨_CD 생성(미배정)/예비배정/본배정/선배정/할당예약/할당확정 , ( SELECT A.SCOLLECT_DT , A.NROUTING_CHK_MST_SEQ , (CASE WHEN A.CASE1 > 1 AND A.CASE2 = 1 THEN 'PIPMS' -- ROUTING 장비 IP 범위가 더 작을 경우(분할) WHEN A.CASE2 > 1 AND A.CASE1 = 1 THEN 'PROUTING' -- IPMS IP 범위가 더 작을 경우(병합) WHEN A.CASE1 = 1 AND A.CASE2 = 1 THEN 'PIPMS' -- IP 범위 같을 경우 ELSE NULL END) AS SIP_PREFIX_GUBUN , (CASE WHEN A.CASE1 > 1 AND A.CASE2 = 1 THEN A.CASE1 -- ROUTING 장비 IP 범위가 더 작을 경우(분할) WHEN A.CASE2 > 1 AND A.CASE1 = 1 THEN A.CASE2 -- IPMS IP 범위가 더 작을 경우(병합) WHEN A.CASE1 = 1 AND A.CASE2 = 1 THEN 0 -- IP 범위 같을 경우 ELSE 0 END) AS NTARGET_CNT , (CASE WHEN A.CASE1 > 1 AND A.CASE2 = 1 THEN 'BIG' -- ROUTING 장비 IP 범위가 더 작을 경우(분할) WHEN A.CASE2 > 1 AND A.CASE1 = 1 THEN 'SMALL' -- IPMS IP 범위가 더 작을 경우(병합) WHEN A.CASE1 = 1 AND A.CASE2 = 1 THEN 'SAME' -- IP 범위 같을 경우 ELSE NULL END) AS SIP_GUBUN FROM ( SELECT A.SCOLLECT_DT , A.NROUTING_CHK_MST_SEQ , COUNT(A.PIPMS_IP_PREFIX) OVER(PARTITION BY A.SCOLLECT_DT, A.SSVC_LINE_TYPE_CD, A.PIPMS_IP_PREFIX) AS CASE1 , COUNT(A.PROUTING_IP_PREFIX) OVER(PARTITION BY A.SCOLLECT_DT, A.SSVC_LINE_TYPE_CD, A.PROUTING_IP_PREFIX) AS CASE2 FROM MST.TB_INTGRM_ROUTING_CHK_MST A WHERE 1=1 AND A.SCHANGE_YN = 'N' -- IP배정, IP할당 메뉴에서 변경이 일어난 건은 조회X AND (A.SCOLLECT_DT, A.NLVL_MST_SEQ) IN ( SELECT MAX(A.SCOLLECT_DT), A.NLVL_MST_SEQ FROM MST.TB_INTGRM_ROUTING_CHK_MST A , MST.TB_LVL_MST B WHERE 1=1 AND A.SCHANGE_YN = 'N' -- IP배정, IP할당 메뉴에서 변경이 일어난 건은 조회X AND B.NLVL_MST_SEQ = A.NLVL_MST_SEQ AND (B.SSVC_LINE_TYPE_CD, B.SSVC_GROUP_CD, B.SSVC_OBJ_CD) IN ( SELECT SSVC_LINE_TYPE_CD, SSVC_GROUP_CD, SSVC_OBJ_CD FROM MST.TB_LVL_MST WHERE 1=1
AND NLVL_MST_SEQ = #{nlvlMstSeq, jdbcType=BIGINT}
) GROUP BY A.NLVL_MST_SEQ) ) A WHERE 1=1 ) L , MST.TB_INTGRM_RSLT_CD M -- DB현행화결과 CD WHERE 1=1 AND A.SCHANGE_YN = 'N' -- IP배정, IP할당 메뉴에서 변경이 일어난 건은 조회X AND (A.SCOLLECT_DT, A.NLVL_MST_SEQ) IN ( SELECT MAX(A.SCOLLECT_DT), A.NLVL_MST_SEQ FROM MST.TB_INTGRM_ROUTING_CHK_MST A , MST.TB_LVL_MST B WHERE 1=1 AND A.SCHANGE_YN = 'N' -- IP배정, IP할당 메뉴에서 변경이 일어난 건은 조회X AND B.NLVL_MST_SEQ = A.NLVL_MST_SEQ AND (B.SSVC_LINE_TYPE_CD, B.SSVC_GROUP_CD, B.SSVC_OBJ_CD) IN ( SELECT SSVC_LINE_TYPE_CD, SSVC_GROUP_CD, SSVC_OBJ_CD FROM MST.TB_LVL_MST WHERE 1=1
AND NLVL_MST_SEQ = #{nlvlMstSeq, jdbcType=BIGINT}
) GROUP BY A.NLVL_MST_SEQ) AND B.NIP_ASSIGN_MST_SEQ(+) = NVL(A.NIP_CHG_ASSIGN_MST_SEQ, A.NIP_ASSIGN_MST_SEQ) AND C.NIP_ASSIGN_MST_SEQ(+) = NVL(A.NIP_CHG_ASSIGN_MST_SEQ, A.NIP_ASSIGN_MST_SEQ) AND C.NIP_ALLOC_MST_SEQ(+) = NVL(A.NIP_CHG_ALLOC_MST_SEQ, A.NIP_ALLOC_MST_SEQ) AND D.NLVL_MST_SEQ = A.NLVL_MST_SEQ AND E.SLVL_CD(+) = D.SSVC_GROUP_CD AND F.SLVL_CD(+) = D.SSVC_OBJ_CD AND G.SSVC_LINE_TYPE_CD(+) = D.SSVC_LINE_TYPE_CD AND H.SIP_CREATE_TYPE_CD(+) = B.SIP_CREATE_TYPE_CD AND I.SASSIGN_TYPE_CD(+) = B.SASSIGN_TYPE_CD AND J.SASSIGN_LEVEL_CD(+) = B.SASSIGN_LEVEL_CD AND L.SCOLLECT_DT(+) = A.SCOLLECT_DT AND L.NROUTING_CHK_MST_SEQ(+) = A.NROUTING_CHK_MST_SEQ AND M.SDB_INTGRM_RSLT_CD(+) = A.SDB_INTGRM_RSLT_CD AND A.SSVC_LINE_TYPE_CD = #{ssvcLineTypeCd, jdbcType=CHAR} AND B.SIP_CREATE_TYPE_CD = #{sipCreateTypeCd, jdbcType=CHAR} AND (CASE WHEN A.SDB_INTGRM_RSLT_CD = 'DR0002' OR A.SDB_INTGRM_RSLT_CD = 'DR0004' THEN 0 WHEN A.SDB_INTGRM_RSLT_CD IS NULL THEN L.NTARGET_CNT ELSE L.NTARGET_CNT END) > 0
AND ( CAST(A.PROUTING_IP_PREFIX AS TEXT) IN
#{item}
OR CAST(A.PIPMS_IP_PREFIX AS TEXT) IN
#{item}
)
AND CAST(A.PROUTING_IP_PREFIX AS TEXT) = #{proutingIpPrefix, jdbcType=VARCHAR}
ORDER BY A.NROUTING_CHK_MST_SEQ , B.PIP_PREFIX

SELECT COUNT(*) FROM MST.TB_INTGRM_ROUTING_CHK_MST A -- 라우팅_비교_결과_MST , MST.TB_IP_ASSIGN_MST B -- IP_배정_MST , MST.TB_IP_ALLOC_MST C -- IP_할당_MST , MST.TB_LVL_MST D -- 계위_MST_수동계위포함 , MST.TB_LVL_CD E -- 국사/조직코드_수동포함 , MST.TB_LVL_CD F -- 국사/조직코드_수동포함 , MST.TB_SVC_LINE_TYPE_CD G -- 서비스_망_유형_CD , MST.TB_IP_CREATE_TYPE_CD H -- IP_생성_유형_CD , MST.TB_ASSIGN_TYPE_CD I -- IP_SVC_할당유형_CD 코넷-기업-고정 , MST.TB_ASSIGN_LEVEL_CD J -- 단계레벨_CD 생성(미배정)/예비배정/본배정/선배정/할당예약/할당확정 , ( SELECT A.SCOLLECT_DT , A.NROUTING_CHK_MST_SEQ , (CASE WHEN A.CASE1 > 1 AND A.CASE2 = 1 THEN 'PIPMS' -- ROUTING 장비 IP 범위가 더 작을 경우(분할) WHEN A.CASE2 > 1 AND A.CASE1 = 1 THEN 'PROUTING' -- IPMS IP 범위가 더 작을 경우(병합) WHEN A.CASE1 = 1 AND A.CASE2 = 1 THEN 'PIPMS' -- IP 범위 같을 경우 ELSE NULL END) AS SIP_PREFIX_GUBUN , (CASE WHEN A.CASE1 > 1 AND A.CASE2 = 1 THEN A.CASE1 -- ROUTING 장비 IP 범위가 더 작을 경우(분할) WHEN A.CASE2 > 1 AND A.CASE1 = 1 THEN A.CASE2 -- IPMS IP 범위가 더 작을 경우(병합) WHEN A.CASE1 = 1 AND A.CASE2 = 1 THEN 0 -- IP 범위 같을 경우 ELSE 0 END) AS NTARGET_CNT , (CASE WHEN A.CASE1 > 1 AND A.CASE2 = 1 THEN 'BIG' -- ROUTING 장비 IP 범위가 더 작을 경우(분할) WHEN A.CASE2 > 1 AND A.CASE1 = 1 THEN 'SMALL' -- IPMS IP 범위가 더 작을 경우(병합) WHEN A.CASE1 = 1 AND A.CASE2 = 1 THEN 'SAME' -- IP 범위 같을 경우 ELSE NULL END) AS SIP_GUBUN FROM ( SELECT A.SCOLLECT_DT , A.NROUTING_CHK_MST_SEQ , COUNT(A.PIPMS_IP_PREFIX) OVER(PARTITION BY A.SCOLLECT_DT, A.SSVC_LINE_TYPE_CD, A.PIPMS_IP_PREFIX) AS CASE1 , COUNT(A.PROUTING_IP_PREFIX) OVER(PARTITION BY A.SCOLLECT_DT, A.SSVC_LINE_TYPE_CD, A.PROUTING_IP_PREFIX) AS CASE2 FROM MST.TB_INTGRM_ROUTING_CHK_MST A WHERE 1=1 AND A.SCHANGE_YN = 'N' -- IP배정, IP할당 메뉴에서 변경이 일어난 건은 조회X AND (A.SCOLLECT_DT, A.NLVL_MST_SEQ) IN ( SELECT MAX(A.SCOLLECT_DT), A.NLVL_MST_SEQ FROM MST.TB_INTGRM_ROUTING_CHK_MST A , MST.TB_LVL_MST B WHERE 1=1 AND A.SCHANGE_YN = 'N' -- IP배정, IP할당 메뉴에서 변경이 일어난 건은 조회X AND B.NLVL_MST_SEQ = A.NLVL_MST_SEQ AND (B.SSVC_LINE_TYPE_CD, B.SSVC_GROUP_CD, B.SSVC_OBJ_CD) IN ( SELECT SSVC_LINE_TYPE_CD, SSVC_GROUP_CD, SSVC_OBJ_CD FROM MST.TB_LVL_MST WHERE 1=1
AND NLVL_MST_SEQ = #{nlvlMstSeq, jdbcType=BIGINT}
) GROUP BY A.NLVL_MST_SEQ) ) A WHERE 1=1 ) L , MST.TB_INTGRM_RSLT_CD M -- DB현행화결과 CD WHERE 1=1 AND A.SCHANGE_YN = 'N' -- IP배정, IP할당 메뉴에서 변경이 일어난 건은 조회X AND (A.SCOLLECT_DT, A.NLVL_MST_SEQ) IN ( SELECT MAX(A.SCOLLECT_DT), A.NLVL_MST_SEQ FROM MST.TB_INTGRM_ROUTING_CHK_MST A , MST.TB_LVL_MST B WHERE 1=1 AND B.NLVL_MST_SEQ = A.NLVL_MST_SEQ AND (B.SSVC_LINE_TYPE_CD, B.SSVC_GROUP_CD, B.SSVC_OBJ_CD) IN ( SELECT SSVC_LINE_TYPE_CD, SSVC_GROUP_CD, SSVC_OBJ_CD FROM MST.TB_LVL_MST WHERE 1=1
AND NLVL_MST_SEQ = #{nlvlMstSeq, jdbcType=BIGINT}
) GROUP BY A.NLVL_MST_SEQ) AND B.NIP_ASSIGN_MST_SEQ(+) = NVL(A.NIP_CHG_ASSIGN_MST_SEQ, A.NIP_ASSIGN_MST_SEQ) AND C.NIP_ASSIGN_MST_SEQ(+) = NVL(A.NIP_CHG_ASSIGN_MST_SEQ, A.NIP_ASSIGN_MST_SEQ) AND C.NIP_ALLOC_MST_SEQ(+) = NVL(A.NIP_CHG_ALLOC_MST_SEQ, A.NIP_ALLOC_MST_SEQ) AND D.NLVL_MST_SEQ = A.NLVL_MST_SEQ AND E.SLVL_CD(+) = D.SSVC_GROUP_CD AND F.SLVL_CD(+) = D.SSVC_OBJ_CD AND G.SSVC_LINE_TYPE_CD(+) = D.SSVC_LINE_TYPE_CD AND H.SIP_CREATE_TYPE_CD(+) = B.SIP_CREATE_TYPE_CD AND I.SASSIGN_TYPE_CD(+) = B.SASSIGN_TYPE_CD AND J.SASSIGN_LEVEL_CD(+) = B.SASSIGN_LEVEL_CD AND L.SCOLLECT_DT(+) = A.SCOLLECT_DT AND L.NROUTING_CHK_MST_SEQ(+) = A.NROUTING_CHK_MST_SEQ AND M.SDB_INTGRM_RSLT_CD(+) = A.SDB_INTGRM_RSLT_CD AND A.SSVC_LINE_TYPE_CD = #{ssvcLineTypeCd, jdbcType=CHAR} AND B.SIP_CREATE_TYPE_CD = #{sipCreateTypeCd, jdbcType=CHAR} AND (CASE WHEN A.SDB_INTGRM_RSLT_CD = 'DR0002' OR A.SDB_INTGRM_RSLT_CD = 'DR0004' THEN 0 WHEN A.SDB_INTGRM_RSLT_CD IS NULL THEN L.NTARGET_CNT ELSE L.NTARGET_CNT END) > 0
